import AVFoundation
import UserNotifications
import StoreKit

// MARK: - Native Bridge Message Types

enum NativeAction: String {
    case openCamera
    case requestCameraPermission
    case requestPushNotifications
    case getPushToken
    case initiateInAppPurchase
    case restorePurchases
    case getDeviceInfo
    case hapticFeedback
    case shareContent
    case openSettings
}

struct BridgeMessage {
    let action: NativeAction
    let payload: [String: Any]
    let callbackId: String?
}

// MARK: - WebView Bridge Controller

class HybridWebViewController: UIViewController {
    
    // MARK: - Properties
    
    private var webView: WKWebView!
    private let websiteURL = "https://your-mobile-website.com"
    private let messageHandlerName = "nativeBridge"
    private var pushToken: String?
    
    // In-App Purchase
    private var products: [SKProduct] = []
    private var pendingPurchaseCallbackId: String?
    
    // MARK: - Lifecycle
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        setupInAppPurchases()
        loadWebsite()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        navigationController?.setNavigationBarHidden(true, animated: animated)
    }
    
    deinit {
        webView?.configuration.userContentController.removeScriptMessageHandler(forName: messageHandlerName)
        webView?.configuration.userContentController.removeScriptMessageHandler(forName: "\(messageHandlerName)Error")
        SKPaymentQueue.default().remove(self)
    }
    
    // MARK: - Setup
    
    private func setupWebView() {
        let configuration = WKWebViewConfiguration()
        
        // Enable JavaScript
        let preferences = WKWebpagePreferences()
        preferences.allowsContentJavaScript = true
        configuration.defaultWebpagePreferences = preferences
        
        // Legacy preferences
        configuration.preferences.javaScriptCanOpenWindowsAutomatically = true
        
        // Allow inline media playback
        configuration.allowsInlineMediaPlayback = true
        configuration.mediaTypesRequiringUserActionForPlayback = []
        
        // Setup user content controller with message handlers
        let userContentController = WKUserContentController()
        userContentController.add(LeakAvoider(delegate: self), name: messageHandlerName)
        
        // Inject JavaScript bridge interface
        let bridgeScript = createBridgeScript()
        let userScript = WKUserScript(source: bridgeScript, injectionTime: .atDocumentStart, forMainFrameOnly: false)
        userContentController.addUserScript(userScript)
        
        configuration.userContentController = userContentController
        
        // Data store for cookies/session persistence
        configuration.websiteDataStore = WKWebsiteDataStore.default()
        
        // Process pool (shared for cookie handling)
        configuration.processPool = WKProcessPool()
        
        // Create WebView
        webView = WKWebView(frame: view.bounds, configuration: configuration)
        webView.translatesAutoresizingMaskIntoConstraints = false
        webView.navigationDelegate = self
        webView.uiDelegate = self
        webView.allowsBackForwardNavigationGestures = true
        webView.scrollView.bounces = true
        webView.scrollView.contentInsetAdjustmentBehavior = .automatic
        
        // Allow inspecting in Safari dev tools (debug only)
        #if DEBUG
        if #available(iOS 16.4, *) {
            webView.isInspectable = true
        }
        #endif
        
        view.addSubview(webView)
        
        NSLayoutConstraint.activate([
            webView.topAnchor.constraint(equalTo: view.topAnchor),
            webView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            webView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            webView.trailingAnchor.constraint(equalTo: view.trailingAnchor)
        ])
        
        // Pull to refresh
        let refreshControl = UIRefreshControl()
        refreshControl.addTarget(self, action: #selector(handleRefresh(_:)), for: .valueChanged)
        webView.scrollView.refreshControl = refreshControl
    }
    
    private func setupInAppPurchases() {
        SKPaymentQueue.default().add(self)
    }
    
    private func createBridgeScript() -> String {
        return """
        (function() {
            window.NativeBridge = {
                _callbackCounter: 0,
                _callbacks: {},
                
                _generateCallbackId: function() {
                    return 'cb_' + (++this._callbackCounter) + '_' + Date.now();
                },
                
                _sendMessage: function(action, payload, callback) {
                    var callbackId = null;
                    if (callback) {
                        callbackId = this._generateCallbackId();
                        this._callbacks[callbackId] = callback;
                    }
                    
                    var message = {
                        action: action,
                        payload: payload || {},
                        callbackId: callbackId
                    };
                    
                    window.webkit.messageHandlers.\(messageHandlerName).postMessage(message);
                },
                
                _receiveCallback: function(callbackId, success, data) {
                    var callback = this._callbacks[callbackId];
                    if (callback) {
                        callback(success, data);
                        delete this._callbacks[callbackId];
                    }
                },
                
                // Emit events to web layer
                _emitEvent: function(eventName, data) {
                    var event = new CustomEvent('nativeBridge:' + eventName, { detail: data });
                    window.dispatchEvent(event);
                },
                
                // --- Public API ---
                
                openCamera: function(callback) {
                    this._sendMessage('openCamera', {}, callback);
                },
                
                requestCameraPermission: function(callback) {
                    this._sendMessage('requestCameraPermission', {}, callback);
                },
                
                requestPushNotifications: function(callback) {
                    this._sendMessage('requestPushNotifications', {}, callback);
                },
                
                getPushToken: function(callback) {
                    this._sendMessage('getPushToken', {}, callback);
                },
                
                initiateInAppPurchase: function(productId, callback) {
                    this._sendMessage('initiateInAppPurchase', { productId: productId }, callback);
                },
                
                restorePurchases: function(callback) {
                    this._sendMessage('restorePurchases', {}, callback);
                },
                
                getDeviceInfo: function(callback) {
                    this._sendMessage('getDeviceInfo', {}, callback);
                },
                
                hapticFeedback: function(style) {
                    this._sendMessage('hapticFeedback', { style: style || 'medium' });
                },
                
                shareContent: function(text, url, callback) {
                    this._sendMessage('shareContent', { text: text, url: url }, callback);
                },
                
                openSettings: function() {
                    this._sendMessage('openSettings', {});
                },
                
                isNativeApp: function() {
                    return true;
                }
            };
            
            // Notify web app that bridge is ready
            window.dispatchEvent(new Event('nativeBridgeReady'));
        })();
        """
    }
    
    // MARK: - Website Loading
    
    private func loadWebsite() {
        guard let url = URL(string: websiteURL) else {
            showError("Invalid URL configuration")
            return
        }
        
        var request = URLRequest(url: url)
        request.cachePolicy = .returnCacheDataElseLoad
        request.addValue("ios-hybrid-app", forHTTPHeaderField: "X-App-Platform")
        request.addValue(appVersion(), forHTTPHeaderField: "X-App-Version")
        
        webView.load(request)
    }
    
    @objc private func handleRefresh(_ refreshControl: UIRefreshControl) {
        webView.reload()
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) {
            refreshControl.endRefreshing()
        }
    }
    
    // MARK: - Native Action Handlers
    
    private func handleNativeMessage(_ message: BridgeMessage) {
        switch message.action {
        case .openCamera:
            handleOpenCamera(callbackId: message.callbackId)
            
        case .requestCameraPermission:
            handleCameraPermission(callbackId: message.callbackId)
            
        case .requestPushNotifications:
            handlePushNotificationRequest(callbackId: message.callbackId)
            
        case .getPushToken:
            handleGetPushToken(callbackId: message.callbackId)
            
        case .initiateInAppPurchase:
            handleInAppPurchase(payload: message.payload, callbackId: message.callbackId)
            
        case .restorePurchases:
            handleRestorePurchases(callbackId: message.callbackId)
            
        case .getDeviceInfo:
            handleGetDeviceInfo(callbackId: message.callbackId)
            
        case .hapticFeedback:
            handleHapticFeedback(payload: message.payload)
            
        case .shareContent:
            handleShareContent(payload: message.payload, callbackId: message.callbackId)
            
        case .openSettings:
            handleOpenSettings()
        }
    }
    
    // MARK: Camera
    
    private func handleCameraPermission(callbackId: String?) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch status {
        case .authorized:
            sendCallback(callbackId: callbackId, success: true, data: ["status": "authorized"])
            
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    self?.sendCallback(
                        callbackId: callbackId,
                        success: granted,
                        data: ["status": granted ? "authorized" : "denied"]
                    )
                }
            }
            
        case .denied, .restricted:
            sendCallback(callbackId: callbackId, success: false, data: ["status": "denied"])
            
        @unknown default:
            sendCallback(callbackId: callbackId, success: false, data: ["status": "unknown"])
        }
    }
    
    private func handleOpenCamera(callbackId: String?) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        guard status == .authorized else {
            handleCameraPermission(callbackId: callbackId)
            return
        }
        
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Camera not available"])
            return
        }
        
        let picker = UIImagePickerController()
        picker.sourceType = .camera
        picker.delegate = self
        picker.allowsEditing = true
        
        // Store callback ID for later use
        objc_setAssociatedObject(picker, "callbackId", callbackId, .OBJC_ASSOCIATION_RETAIN)
        
        present(picker, animated: true)
    }
    
    // MARK: Push Notifications
    
    private func handlePushNotificationRequest(callbackId: String?) {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if granted {
                    UIApplication.shared.registerForRemoteNotifications()
                    self?.sendCallback(callbackId: callbackId, success: true, data: ["granted": true])
                } else {
                    self?.sendCallback(
                        callbackId: callbackId,
                        success: false,
                        data: ["granted": false, "error": error?.localizedDescription ?? "Permission denied"]
                    )
                }
            }
        }
    }
    
    private func handleGetPushToken(callbackId: String?) {
        if let token = pushToken {
            sendCallback(callbackId: callbackId, success: true, data: ["token": token])
        } else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "No push token available"])
        }
    }
    
    func updatePushToken(_ token: String) {
        self.pushToken = token
        emitEvent(name: "pushTokenUpdated", data: ["token": token])
    }
    
    func handlePushNotification(userInfo: [AnyHashable: Any]) {
        emitEvent(name: "pushNotificationReceived", data: userInfo as? [String: Any] ?? [:])
    }
    
    // MARK: In-App Purchases
    
    private func handleInAppPurchase(payload: [String: Any], callbackId: String?) {
        guard let productId = payload["productId"] as? String else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Missing productId"])
            return
        }
        
        guard SKPaymentQueue.canMakePayments() else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "In-app purchases are disabled"])
            return
        }
        
        pendingPurchaseCallbackId = callbackId
        
        // Fetch product first
        let productRequest = SKProductsRequest(productIdentifiers: Set([productId]))
        productRequest.delegate = self
        productRequest.start()
    }
    
    private func handleRestorePurchases(callbackId: String?) {
        pendingPurchaseCallbackId = callbackId
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    // MARK: Device Info
    
    private func handleGetDeviceInfo(callbackId: String?) {
        let device = UIDevice.current
        let info: [String: Any] = [
            "model": device.model,
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "name": device.name,
            "identifierForVendor": device.identifierForVendor?.uuidString ?? "",
            "appVersion": appVersion(),
            "buildNumber": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "",
            "bundleId": Bundle.main.bundleIdentifier ?? "",
            "screenWidth": UIScreen.main.bounds.width,
            "screenHeight": UIScreen.main.bounds.height,
            "screenScale": UIScreen.main.scale,
            "isSimulator": isSimulator()
        ]
        
        sendCallback(callbackId: callbackId, success: true, data: info)
    }
    
    // MARK: Haptic Feedback
    
    private func handleHapticFeedback(payload: [String: Any]) {
        let style = payload["style"] as? String ?? "medium"
        
        switch style {
        case "light":
            let generator = UIImpactFeedbackGenerator(style: .light)
            generator.impactOccurred()
        case "medium":
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        case "heavy":
            let generator = UIImpactFeedbackGenerator(style: .heavy)
            generator.impactOccurred()
        case "success":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.success)
        case "warning":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.warning)
        case "error":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.error)
        case "selection":
            let generator = UISelectionFeedbackGenerator()
            generator.selectionChanged()
        default:
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        }
    }
    
    // MARK: Share
    
    private func handleShareContent(payload: [String: Any], callbackId: String?) {
        var activityItems: [Any] = []
        
        if let text = payload["text"] as? String {
            activityItems.append(text)
        }
        if let urlString = payload["url"] as? String, let url = URL(string: urlString) {
            activityItems.append(url)
        }
        
        guard !activityItems.isEmpty else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Nothing to share"])
            return
        }
        
        let activityVC = UIActivityViewController(activityItems: activityItems, applicationActivities: nil)
        
        // iPad support
        if let popover = activityVC.popoverPresentationController {
            popover.sourceView = webView
            popover.sourceRect = CGRect(x: view.bounds.midX, y: view.bounds.midY, width: 0, height: 0)
        }
        
        activityVC.completionWithItemsHandler = { [weak self] _, completed, _, error in
            self?.sendCallback(
                callbackId: callbackId,
                success: completed,
                data: ["completed": completed, "error": error?.localizedDescription as Any]
            )
        }
        
        present(activityVC, animated: true)
    }
    
    // MARK: Settings
    
    private func handleOpenSettings() {
        if let settingsURL = URL(string: UIApplication.openSettingsURLString) {
            UIApplication.shared.open(settingsURL)
        }
    }
    
    // MARK: - JavaScript Communication
    
    private func sendCallback(callbackId: String?, success: Bool, data: [String: Any]) {
        guard let callbackId = callbackId else { return }
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data),
              let jsonString = String(data: jsonData, encoding: .utf8) else {
            return
        }
        
        let script = "window.NativeBridge._receiveCallback('\(callbackId)', \(success), \(jsonString));"
        
        DispatchQueue.main.async { [weak self] in
            self?.webView.evaluateJavaScript(script) { _, error in
                if let error = error {
                    print("[HybridBridge] Callback error: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func emitEvent(name: String, data: [String: Any]) {
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data),
              let jsonString = String(data: jsonData, encoding: .utf8) else {
            return
        }
        
        let script = "window.NativeBridge._emitEvent('\(name)', \(jsonString));"
        
        DispatchQueue.main.async { [weak self] in
            self?.webView.evaluateJavaScript(script, completionHandler: nil)
        }
    }
    
    // MARK: - Helpers
    
    private func appVersion() -> String {
        return Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0.0"
    }
    
    private func isSimulator() -> Bool {
        #if targetEnvironment(simulator)
        return true
        #else
        return false
        #endif
    }
    
    private func showError(_ message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        alert.addAction(UIAlertAction(title: "Retry", style: .default) { [weak self] _ in
            self?.loadWebsite()
        })
        present(alert, animated: true)
    }
    
    // MARK: - Public Methods
    
    func evaluateJavaScript(_ script: String, completion: ((Any?, Error?) -> Void)? = nil) {
        webView.evaluateJavaScript(script, completionHandler: completion)
    }
    
    func goBack() -> Bool {
        if webView.canGoBack {
            webView.goBack()
            return true
        }
        return false
    }
}

// MARK: - WKScriptMessageHandler

extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard message.name == messageHandlerName,
              let body = message.body as? [String: Any],
              let actionString = body["action"] as? String,
              let action = NativeAction(rawValue: actionString) else {
            print("[HybridBridge] Invalid message received: \(message.body)")
            return
        }
        
        let payload = body["payload"] as? [String: Any] ?? [:]
        let callbackId = body["callbackId"] as? String
        
        let bridgeMessage = BridgeMessage(action: action, payload: payload, callbackId: callbackId)
        
        print("[HybridBridge] Received action: \(actionString), callbackId: \(callbackId ?? "none")")
        
        handleNativeMessage(bridgeMessage)
    }
}

// MARK: - WKNavigationDelegate

extension HybridWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        UIApplication.shared.isNetworkActivityIndicatorEnabled = true
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        UIApplication.shared.isNetworkActivityIndicatorEnabled = false
        webView.scrollView.refreshControl?.endRefreshing()
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        UIApplication.shared.isNetworkActivityIndicatorEnabled = false
        webView.scrollView.refreshControl?.endRefreshing()
        
        let nsError = error as NSError
        // Ignore cancelled navigation
        if nsError.code == NSURLErrorCancelled { return }
        
        showError("Failed to load: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        UIApplication.shared.isNetworkActivityIndicatorEnabled = false
        webView.scrollView.refreshControl?.endRefreshing()
        
        let nsError = error as NSError
        if nsError.code == NSURLErrorCancelled { return }
        
        showError("Failed to load: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Handle external links (open in Safari)
        let urlString = url.absoluteString
        if let host = url.host,
           !host.contains("your-mobile-website.com") &&
            !host.contains("localhost") &&
            url.scheme == "https" || url.scheme == "http" {
            
            // Allow certain domains to load in-app
            let allowedDomains = ["your-cdn.com", "your-auth-provider.com"]
            if allowedDomains.contains(where: { host.contains($0) }) {
                decisionHandler(.allow)
                return
            }
            
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        // Handle custom URL schemes
        if let scheme = url.scheme, !["http", "https", "about", "blob"].contains(scheme) {
            switch scheme {
            case "tel", "mailto", "sms":
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            default:
                break
            }
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationResponse: WKNavigationResponse, decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        decisionHandler(.allow)
    }
}

// MARK: - WKUIDelegate

extension HybridWebViewController: WKUIDelegate {
    
    // Handle JavaScript alerts
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript confirms
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript prompts
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        let alert = UIAlertController(title: nil, message: prompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
    
    // Handle window.open
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil || !(navigationAction.targetFrame?.isMainFrame ?? false) {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

// MARK: - UIImagePickerControllerDelegate

extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey: Any]) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String
        
        if let image = info[.editedImage] as? UIImage ?? info[.originalImage] as? UIImage {
            // Convert to base64
            if let imageData = image.jpegData(compressionQuality: 0.8) {
                let base64String = imageData.base64EncodedString()
                sendCallback(callbackId: callbackId, success: true, data: [
                    "imageBase64": "data:image/jpeg;base64,\(base64String)",
                    "width": image.size.width,
                    "height": image.size.height
                ])
            } else {
                sendCallback(callbackId: callbackId, success: false, data: ["error": "Failed to process image"])
            }
        } else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "No image selected"])
        }
        
        picker.dismiss(animated: true)
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String
        sendCallback(callbackId: callbackId, success: false, data: ["error": "User cancelled"])
        picker.dismiss(animated: true)
    }
}

// MARK: - SKProductsRequestDelegate

extension HybridWebViewController: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        products = response.products
        
        if let product = response.products.first {
            let payment = SKPayment(product: product)
            SKPaymentQueue.default().add(payment)
        } else {
            sendCallback(callbackId: pendingPurchaseCallbackId, success: false, data: ["error": "Product not found"])
            pendingPurchaseCallbackId = nil
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        sendCallback(callbackId: pendingPurchaseCallbackId, success: false, data: ["error": error.localizedDescription])
        pendingPurchaseCallbackId = nil
    }
}

// MARK: - SKPaymentTransactionObserver

extension HybridWebViewController: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                let receiptData = Bundle.main.appStoreReceiptURL.flatMap { try? Data(contentsOf: $0) }
                let receiptString = receiptData?.base64EncodedString() ?? ""
                
                sendCallback(callbackId: pendingPurchaseCallbackId, success: true, data: [
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "productId": transaction.payment.productIdentifier,
                    "receipt": receiptString,
                    "state": "purchased"
                ])
                
                SKPaymentQueue.default().finishTransaction(transaction)
                pendingPurchaseCallbackId = nil
                
            case .failed:
                sendCallback(callbackId: pendingPurchaseCallbackId, success: false, data: [
                    "error": transaction.error?.localizedDescription ?? "Purchase failed",
                    "state": "failed"
                ])
                
                SKPaymentQueue.default().finishTransaction(transaction)
                pendingPurchaseCallbackId = nil
                
            case .restored:
                sendCallback(callbackId: pendingPurchaseCallbackId, success: true, data: [
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "productId": transaction.payment.productIdentifier,
                    "originalTransactionId": transaction.original?.transactionIdentifier ?? "",
                    "state": "restored"
                ])
                
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .deferred:
                emitEvent(name: "purchaseDeferred", data: [
                    "productId": transaction.payment.productIdentifier
                ])
                
            case .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        if queue.transactions.isEmpty {
            sendCallback(callbackId: pendingPurchaseCallbackId, success: true, data: [
                "restored": false,
                "message": "No purchases to restore"
            ])
        }
        pendingPurchaseCallbackId = nil
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        sendCallback(callbackId: pendingPurchaseCallbackId, success: false, data: [
            "error": error.localizedDescription
        ])
        pendingPurchaseCallbackId = nil
    }
}

// MARK: - LeakAvoider (prevents retain cycle with WKUserContentController)

class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - AppDelegate Integration Helper

extension HybridWebViewController {
    
    /// Call this from AppDelegate when push token is received
    static func handleDeviceToken(_ deviceToken: Data) -> String {
        let tokenParts = deviceToken.map { data in String(format: "%02.2hhx", data) }
        return tokenParts.joined()
    }
}

